console.log(isEmpty({ a: 1 }));        // false
console.log(isEmpty(new Date()));      // false (constructor check)
console.log(isEmpty(null));            // throws! (add null check)

// Safer version:
function isEmptySafe(obj) {
  return obj != null &&
    typeof obj === 'object' &&
    !Array.isArray(obj) &&
    Object.keys(obj).length === 0;
}

