// Multi-word (capitalize each word)
function capitalizeWords(str) {
  return str.split(' ').map(w =>
    w.charAt(0).toUpperCase() + w.slice(1)
  ).join(' ');
}
console.log(capitalizeWords('hello world')); // 'Hello World'

